app = FastAPI(lifespan=lifespan)

security = HTTPBearer(auto_error=False)

class TokenValidator:
    def __init__(self, redis_client: redis.Redis):
        self.redis_client = redis_client
    
    async def validate_token(self, token: str) -> Dict[str, Any]:
        if not self.redis_client:
            raise HTTPException(
                status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
                detail="Token validation service unavailable"
            )
        
        try:
            token_data = await self.redis_client.get(f"token:{token}")
            
            if not token_data:
                raise HTTPException(
                    status_code=status.HTTP_401_UNAUTHORIZED,
                    detail="Invalid or expired token",
                    headers={"WWW-Authenticate": "Bearer"}
                )
            
            token_info = json.loads(token_data)
            
            if 'expires_at' in token_info:
                expires_at = datetime.fromisoformat(token_info['expires_at'])
                if datetime.utcnow() > expires_at:
                    await self.redis_client.delete(f"token:{token}")
                    raise HTTPException(
                        status_code=status.HTTP_401_UNAUTHORIZED,
                        detail="Token has expired",
                        headers={"WWW-Authenticate": "Bearer"}
                    )
            
            return token_info
            
        except json.JSONDecodeError:
            raise HTTPException(
                status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
                detail="Token data corrupted"
            )
        except HTTPException:
            raise
        except Exception as e:
            raise HTTPException(
                status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
                detail=f"Token validation error: {str(e)}"
            )

async def get_token_validator() -> TokenValidator:
    return TokenValidator(redis_client)

async def get_current_user(
    credentials: Optional[HTTPAuthorizationCredentials] = Depends(security),
    validator: TokenValidator = Depends(get_token_validator)
) -> Dict[str, Any]:
    if not credentials:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Missing authentication credentials",
            headers={"WWW-Authenticate": "Bearer"}
        )
    
    if credentials.scheme.lower() != "bearer":
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid authentication scheme",
            headers={"WWW-Authenticate": "Bearer"}
        )
    
    token = credentials.credentials
    token_info = await validator.validate_token(token)
    
    return token_info

async def get_optional_user(
    credentials: Optional[HTTPAuthorizationCredentials] = Depends(security),
    validator: TokenValidator = Depends(get_token_validator)
) -> Optional[Dict[str, Any]]:
    if not credentials:
        return None
    
    try:
        token = credentials.credentials
        token_info = await validator.validate_token(token)
        return token_info
    except HTTPException:
        return None

async def require_scope(required_scope: str):
    async def scope_checker(
        current_user: Dict[str, Any] = Depends(get_current_user)
    ) -> Dict[str, Any]:
        user_scopes = current_user.get('scopes', [])
        if required_scope not in user_scopes:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail=f"Insufficient permissions. Required scope: {required_scope}"
            )
        return current_user
    return scope_checker

