@app.get("/health")
async def health_check():
    redis_status = "healthy"
    try:
        if redis_client:
            await redis_client.ping()
        else:
            redis_status = "unavailable"
    except Exception as e:
        redis_status = f"unhealthy: {str(e)}"
    
    return {
        "status": "ok" if redis_status == "healthy" else "degraded",
        "redis": redis_status
    }